const Q_PHYSICS_1994=[{"id": "objective>Physics>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If it takes 5.0 hrs to drain a container of 540.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water, what is the flow rate of water from the container in kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>?  <br/> [Density of water = 1000kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32.5kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">31.5kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.8kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.0kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Flow</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">rate</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />time</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000×540<hr size=\"1\" />5×3600</td></tr></table></div> <br/> = 30.0kgs<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "LIQUIDS AT REST : DENSITY OF SOLID AND LIQUIDS"}, {"id": "objective>Physics>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boat travels due east at a speed 40ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> across a river flow due south at 30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. What is the resultant speed of the boat?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"1994/answerphyq2.png\" style=\"position:relative;max-width:100%;\"/> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 2500 <br/> R = 50m/s</div>", "topic": "SCALARS AND VECTORS : RELATIVE VELOCITY"}, {"id": "objective>Physics>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is projected with a velocity of 80ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to the horizontal.The maximum height reached is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">160m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">320m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">max.</td><td style=\"text-align:center;\">height</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">U<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>θ<hr size=\"1\" />2g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80×80×sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>(30)<hr size=\"1\" />2×10</td></tr></table></div> <br/> = 80m</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A motor vehicle is brought to rest from a speed of 15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in 20 seconds. Calculate the retardation.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.33ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.00ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.50ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Retardation or deceleration is the rate of decrease in velocity. It is calculated as the change in velocity divided by the time taken for this change. In this case, the initial velocity is 15ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, the final velocity is 0 (since the vehicle is brought to rest), and the time taken is 20 seconds. Therefore, the retardation is (0 - 15) / 20 = -0.75ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The negative sign indicates that this is a deceleration.</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is TRUE of a particle moving in a horizontal circle with constant angular velocity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The energy is costant but the linear momentum varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The linear momentum is conatant but the energy varies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both energy and linear momentum are constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The speed and the linear velocity are both constant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A particle moving in a horizontal circle with constant angular velocity has constant energy but varying linear momentum. The energy is constant because the speed of the particle is constant. However, the direction of the velocity (and hence the linear momentum) is constantly changing as the particle moves around the circle, so the linear momentum is not constant.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 50kg is released from a height of 2m.Find the kinetic energy just before it strikes the ground</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">250J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 000J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 000J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P.E = K.E = mgh <br/>  <br/> = 50 x 10 x 2 = 1000J <br/>  <br/> ∴ the kinetic energy just before it strikes the ground is 1000J.</div>", "topic": "WORK ENERGY AND POWER : CONSERVATION OF ENERGY"}, {"id": "objective>Physics>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cone in an unstable equilibrium has its potential energy</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oscillating</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An object in unstable equilibrium has its potential energy increased. This is because in unstable equilibrium, any small displacement will cause the system to depart further from its initial position. Hence, the potential energy is at a maximum.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY~~WORK, ENERGY AND POWER"}, {"id": "objective>Physics>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the magnitude of the force required to just move a 20kg object along a horizontal surface if the coefficient of friction is 0.2.  <br/> [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">400.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force required to move an object along a horizontal surface is given by the formula F = μN, where μ is the coefficient of friction and N is the normal force. In this case, since the object is on a horizontal surface, the normal force is equal to the weight of the object, which is mass times gravity (20kg * 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 200N). Therefore, the force required is μN = 0.2 * 200N = 40.0N.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the velocity ratio of a screw jack of pitch 0.3cm if the length of the tommy bar is 21cm</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />140</td><td style=\"text-align:center;\">π</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">14π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70 π</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140π</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V.R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2πL<hr size=\"1\" />p</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 × π × 21<hr size=\"1\" />0.3</td></tr></table></div> <br/> V.R = 140π</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A force of 15N stretches a spring to a total length of 30cm. An additional force of 10N stretches the spring 5cm further. Find the natural length of the spring</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 15 N, F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 25 N, e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 30 - L, e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 35 - L <br/>  <br/> Since the spring constant does not change, <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">15<hr size=\"1\" />30 − L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25<hr size=\"1\" />35 - L</td></tr></table></div> <br/> 15(35 - L) = 25(30 - L) <br/>  <br/> 525 - 15L = 750 - 25L <br/>  <br/> 25L - 15L = 750 - 525 <br/>  <br/> 10L = 225 <br/>  <br/> L = 22.5cm <br/>  <br/> ∴ the natural length of the spring is 22.5cm.</div>", "topic": "ELASTICITY"}, {"id": "objective>Physics>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these statements are TRUE of pressure in liquids?  <br/> i. pressure acts equally in all direction.  <br/> ii. pressure decreases with depth.  <br/> iii. pressure at the same level of a liquid is the same.  <br/> iv pressure is dependent on the cross-sectional area of the barometer tube</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, iii, and iv only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i, ii, iii and iv</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statements about pressure in liquids are: i. pressure acts equally in all directions. This is known as Pascal's law. ii. pressure increases with depth, not decreases. This is because the pressure in a fluid at any given depth is proportional to the density of the fluid, the acceleration due to gravity, and the depth. iii. pressure at the same level of a liquid is the same. This is because the pressure at any point in a static fluid depends only on the depth at that point, not on the shape of the container or the cross-sectional area. iv. pressure is not dependent on the cross-sectional area of the barometer tube. Therefore, the correct option is 'i, iii only'.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a specific gravity bottle is 15.2g when it is empty. it is 24.8g when filled with kerosene and 27.2g when filled with distilled water. Calculate the relative density of kerosene</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.90</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 0.80</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Masses of kerosene = 24.8 - 15.2 <br/> = 9.6 <br/> mass of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 27.2 - 15.2 = 12 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.6<hr size=\"1\" />12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.8</td></tr></table></div></div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a solid X floats in liquids P of relative density 2.0 and in liquid Q of relative density 1.5, it can be inferred that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weight of P displaced is greater than that of Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weight of P displaced is less than that of Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of P displaced is greater than that of Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of P displaced is less than that of Q</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R.d α weight of liquid displaced <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.d of P<hr size=\"1\" />R.d of Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">weight of p displaced<hr size=\"1\" />weight of Q displaced</td></tr></table></div> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">weight of p displaced<hr size=\"1\" />weight of Q displaced</td></tr></table></div></div>", "topic": "LIQUIDS AT REST : RELATIVE DENSITY"}, {"id": "objective>Physics>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The melting point of naphthalene is 78<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. What is this temperature in kelvin</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">351k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">378k</div>", "<div style=\"font-family:Cambria;font-size:17px;\">444k</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Kelvin scale is an absolute temperature scale starting at absolute zero, the point at which all molecular motion ceases. To convert from Celsius to Kelvin, you add 273.15 to the Celsius temperature. Therefore, 78 degrees Celsius is equal to 78 + 273.15 = 351.15 Kelvin, which is approximately 351 Kelvin.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Motor Tyre is inflated to pressure of 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> when the temperature of air is 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C. What will be the pressure in it at 87<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C assuming that the volume of the Tyre does not change?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.6 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span><hr size=\"1\" />27+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />87+273</td></tr></table></div> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When 100g of liquids L1 at 78°C was mixed with Xg of liquid L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at 50°C, the final temperature was 66°C. Given that the specific heat capacity of L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is half that of L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, find x</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat lost by L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = heat gained by L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> cL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2cL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> 100 x 2cL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x (78 - 66) <br/>  <br/> = xg x cL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>x (66 - 50) <br/>  <br/> xg = 150g</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heat is supplied to a test tube containing 100g of ice at its melting point. The ice melts completely in 1 min.What is the power rating of the source of heat? <br/>  [Latent heat of fusion of ice = 336Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">336W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">560W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600W</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">p x t = heat energy <br/> P x 1 x 60 = 100 x 336 <br/> p = 560W</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a room is saturated with water vapour, the temperature of the room must be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">above the dew point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">below or at the dew point</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If a room is saturated with water vapor, it means the air in the room has the maximum amount of water vapor it can hold at that temperature. If the temperature drops (reaches or goes below the dew point), the air becomes unable to hold all of its moisture, leading to the formation of dew or condensation. Therefore, the temperature of the room must be below or at the dew point for saturation to occur.</div>", "topic": "VAPOURS : DEW POINT, HUMIDITY AND RELATIVE HUMIDITY"}, {"id": "objective>Physics>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two similar kettles containing equal masses of boiling water are placed on a table. If the surface of one is highly polished and the surface of the other is covered with soot, Which of the following observations is correct</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The two kettles will cool down at the same rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the polished kettle cools down more quickly by conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the kettle covered with soot cools down more quickly because it is a good radiator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the kettle covered with soot cools down more quickly by the process of heat convection</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kettle covered with soot cools down more quickly because it is a good radiator. This is because dark surfaces are better radiators of heat than light surfaces. Soot is dark and therefore a good radiator, while a polished surface reflects heat back into the kettle, slowing down the cooling process.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equation of transverse wave traveling along a string is given by Y = 0.3 sin(0.5x - 50t) where Y and X are in cm and t is in seconds.Find the maximum displacement of the particles from the equilibrium position</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.3cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The maximum displacement of the particles from the equilibrium position in a wave is given by the amplitude of the wave. In the given equation Y = 0.3 sin(0.5x - 50t), the amplitude is 0.3cm.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sound from a source travelled to the bottom of the sea and the echo was heard 4s later. If the speed of sound in sea water is 1500ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> the depth of the sea is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">375m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">t = 4s ; v = 150ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> depth = X ; but 2X = vt <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">vt<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1500×4<hr size=\"1\" />2</td></tr></table></div> <br/> X = 3000m</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental frequency of vibration of a sonometer wire may be halved by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">doubling the length of the wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">doubling the mass of the wire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing the tension by half</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing the absolute temperature by half</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental frequency of a vibrating string is given by the formula f = (1/2L) * &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T/μ&nbsp;</span>, where L is the length of the string, T is the tension in the string, and μ is the linear mass density of the string. If we double the length of the string, the fundamental frequency will be halved. This is because the frequency is inversely proportional to the length of the string.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pipe of length 45cm is closed at the end. Calculate the fundamental frequency of the sound wave generated in the pipe if the velocity of sound in air is 360ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> [Neglect end correction]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.5Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">148.5Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200.0Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">550.0Hz</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">λ = 4L = 4 X 45 = 180cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<hr size=\"1\" />λ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">360<hr size=\"1\" />180×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">−2</span></td></tr></table></div> <br/> = 200Hz</div>", "topic": "PROPAGATION OF SOUND WAVES : SPEED OF SOUND"}, {"id": "objective>Physics>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The note produced by a stretched string has a fundamental frequency of 400Hz. If the length of the string is doubled while the tension in the string is increased by a factor of 4, the frequency is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">200Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2L</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />m</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> ; L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />2F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">400×L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />F×L<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />4T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> F = 400Hz</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To produce a parallel beam of light from a concave mirror, the distance at a which the lamp should be placed from the mirror is equal to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the focal length</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two times the focal length</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the distance of the image</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two times the radius of curvature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To produce a parallel beam of light from a concave mirror, the light source (lamp) should be placed at the focal point of the mirror. The focal point is the point where parallel rays of light meet after reflecting off the mirror. Therefore, the correct answer is 'the focal length'.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Light of frequency 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz travelling in air is transmitted through glass or refractive index 1.5. Calculate the frequency of the light in the glass</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span>Hz</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The frequency of light does not change when it passes from one medium to another. This is because frequency is a property of the source of the light and is not affected by the medium it travels through. Therefore, the frequency of the light in the glass remains the same as in air, which is 6.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span> Hz.</div>", "topic": "REFRACTION OF LIGHT THROUGH : GLASS PRISM"}, {"id": "objective>Physics>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed in front of a converging lens of a focal length 20cm. The image is virtual and has a magnification of 2. What is the distance of the object from the lens?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V = -2u <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">uv<hr size=\"1\" />u+v</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">uv−2u<hr size=\"1\" />u−2u</td></tr></table></div> <br/> u = 10cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object is placed directly below a glass block of thickness 3.0cm. Calculate the lateral displacement of the object if the refractive index of the glass is 1.5.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5cm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />apparent displacement</td></tr></table></div> <br/> Apparent depth = 2cm <br/> displacement = 3 - 2 <br/> = 1cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a projection lantern of focal length f, the object distance u, is such that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">u > 2f > f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">u < f < 2f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">u = f < 2f</div>", "<div style=\"font-family:Cambria;font-size:17px;\">f < u < 2f</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a projection lantern, the object is placed at a distance greater than the focal length but less than twice the focal length. This is because the image formed is real, inverted and magnified, which is ideal for projection. Therefore, the correct relation is f < u < 2f.</div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the Nigeria flag (green, white, green) is viewed in pure yellow light, which of the following set of colours would be observed on the flag?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Green, yellow, green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red, yellow, red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black, yellow, black</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green, white, green</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine how the Nigeria flag (green, white, green) would appear when viewed in pure yellow light, we need to consider how colors interact with light. <br/> Step 1: Understand Color Absorption and Reflection <br/> ·\tGreen: Absorbs all colors except green, which it reflects. <br/> ·\tWhite: Reflects all colors. <br/> ·\tYellow Light: Contains a mix of red and green light. <br/> Step 2: Analyze Each Part of the Flag Under Yellow Light <br/> 1.\tGreen Stripe: <br/> o\tUnder yellow light, the green part of the flag will reflect the green component of the yellow light and absorb the red component. <br/> o\tSince yellow light contains green, the green stripe will appear green. <br/> 2.\tWhite Stripe: <br/> o\tWhite reflects all colors, so under yellow light, it will reflect yellow. <br/> o\tThe white stripe will appear yellow. <br/> 3.\tGreen Stripe: <br/> o\tSimilar to the first green stripe, it will reflect the green component of the yellow light and absorb the red component. <br/> o\tThe green stripe will appear green. <br/> Step 3: Conclusion <br/> Under pure yellow light, the Nigeria flag will appear as green, yellow, green. <br/> Final Answer: <br/> Green, yellow, green</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following has the lowest internal resistance when new?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leclanche cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Daniel cell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accumulator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Torch battery</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An accumulator, also known as a rechargeable battery, has the lowest internal resistance when new. Internal resistance is the opposition to the flow of current within the battery itself. The lower the internal resistance, the more efficiently the battery can deliver its stored energy.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a biro pen rubbed on a dry silk cloth is moved very close to a piece of paper on a dry table, the pen is found to pick up the paper. This is because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both the pen and the cloth are magnetized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pen is magnetized but the cloth is not</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pen is charged while the cloth is magnetized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both the pen and the cloth are charged</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a biro pen is rubbed on a dry silk cloth, both the pen and the cloth become charged due to the transfer of electrons. This is a demonstration of the triboelectric effect, where certain materials become electrically charged after they come into frictional contact with a different material. In this case, the pen picks up the paper because of the electrostatic attraction between the charged pen and the paper.</div>", "topic": "ELECTROSTATICS"}, {"id": "objective>Physics>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A capacitor 8μF is charged to a potential difference of 100V. The energy stored by the capacitor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>J</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 8.0 x 10J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25 x 10J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy (E) stored in a capacitor can be calculated using the formula E = 1/2 CV^2, where C is the capacitance and V is the voltage. Substituting the given values, we get E = 1/2 * 8 * 10^-6 F * (100 V)^2 = 4.0 x 10^-2 J.</div>", "topic": "CAPACITORS : ENERGY STORED IN A CAPACITOR"}, {"id": "objective>Physics>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two capacitors R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 4Ω and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 5Ω are connected in parallel across a potential difference. If P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> represent power dissipated in R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> respectively, then the ratio P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> : P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 : 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 : 4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16 : 25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25 : 16</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\"></span></span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 4P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 5P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />p<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />4</td></tr></table></div> <br/> = 5 : 4</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are found in the receiver but not in the microphone of a telephone handset?  <br/> i. Diaphragm.  <br/> ii. soft iron pole pieces.  <br/> iii. permanent magnet.  <br/> iv.carbon blocks</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">i and ii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">i and iv</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ii and iii</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iii and iv</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a telephone handset, the microphone and the receiver have different components. The microphone converts sound waves into electrical signals, while the receiver converts electrical signals back into sound waves. The diaphragm is found in both the microphone and the receiver, as it vibrates in response to sound waves or electrical signals. The soft iron pole pieces and the permanent magnet are found in the receiver, but not in the microphone. They are used to generate a magnetic field that causes the diaphragm to vibrate and produce sound. The carbon blocks are found in the microphone, where they vary the electrical resistance in response to the pressure of sound waves. Therefore, the correct answer is option 3, 'ii and iii'.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two parallel conductors carry currents flowing in the same direction, the conducts will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attract each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">repel each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">both move in the same direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have no effect on each other</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Ampere's law, two parallel conductors carrying currents in the same direction will attract each other. This is because the magnetic field produced by one conductor exerts a force on the other conductor, pulling them towards each other. Therefore, the correct answer is option 1, 'attract each other'.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain radioisotope of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U emits four alpha particles and three beta particles. The mass number and the atomic number of the resulting elements respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">219 and 87</div>", "<div style=\"font-family:Cambria;font-size:17px;\">84 and 223</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 223 and 87</div>", "<div style=\"font-family:Cambria;font-size:17px;\">219 and 81</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U → 4(<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>α) + 3(<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">−1</span>e) + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>y <br/>  <br/> a + (4 × 2) + (3 × - 1) = 92 ⇒ a = 87 <br/>  <br/> b + (4 × 4) + (3 × 0) = 235 ⇒ b = 219 <br/>  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>Y =  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">219</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">87</span>Y</div>", "topic": "ELEMENTARY MODERN PHYSICS : ALPHA, BETA AND GAMMA RAYS"}, {"id": "objective>Physics>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If light with photon energy 2eV is incident suitably on the surface of a metal with work function 3eV, then</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">no electron will be emitted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the few electrons emitted will have a maximum kinetic energy of 1eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the few electrons emitted will have a maximum kinetic energy of 3eV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many electrons will be emitted</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The photoelectric effect is the emission of electrons when light is shone onto a material. The energy of the incident light must be greater than the work function of the material for electrons to be emitted. In this case, the photon energy (2eV) is less than the work function of the metal (3eV), so no electrons will be emitted. Hence, the correct option is 'no electron will be emitted'.</div>", "topic": "ELEMENTARY MODERN PHYSICS : PHOTOELECTRIC EFFECTS"}, {"id": "objective>Physics>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A spring of length 25cm is extended to 30cm by a load of 150N attached to one of its end, what is the energy stored in the spring?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 3750J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2500J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.75J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50J</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The energy stored in a spring is given by the formula 1/2*k*x^2, where k is the spring constant and x is the extension of the spring. The spring constant can be calculated using Hooke's law, which states that the force applied to a spring is directly proportional to the extension of the spring. In this case, the force is 150N and the extension is 0.05m (30cm - 25cm), so the spring constant is 150N/0.05m = 3000N/m. Substituting these values into the formula for the energy stored in the spring gives 1/2*3000N/m*(0.05m)^2 = 3.75J. Hence, the correct option is '3.75J'.</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> What is the reading of the vernier calipers shown above </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.79cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.73cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.39cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.34cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reading of the vernier calipers shown above is: <br/>  <br/> 1.39cm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The fig above shows a uniform wood of weight 200N and length 50m. It is pivoted at one end and suspended by a cord at the other end at an angle of 30 degrees to the wood. calculate the tension in the cord if the wood is horizontal</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200N</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taking the moment at the pivoted end  <br/> 200(25) = Tsin30(50) <br/> 5000 = 25T <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5000<hr size=\"1\" />25</td></tr></table></div> <br/> T = 200N</div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the fig above if the atmospheric pressure is 760mm, the pressure of the chamber G is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">660mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">690mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">830mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">860mm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">p = ρhg <br/> h = h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">G</span> <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">G</span> = 100mm - 30mm = 70mm <br/> h = 760 + 70 = 830mm</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE~~PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the fig above, XY is of length 1m, The value of R at balance point Z is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 13.3Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.0Ω</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.0Ω</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At null deflection, p.d across R = p.d across xz <br/> p.d across 20Ω = p.d across zy  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />40</td></tr></table></div> <br/> R = 30Ω</div>", "topic": "CURRENT ELECTRICITY : POTENTIOMETER"}, {"id": "objective>Physics>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the circuit diagram above, calculate the current in the 12 Ω resistor if the cell has an emf of 12V and an internal resistance of 1Ω </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 0.8A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 1.6A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.4A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E=I(R + r) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R + r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />12</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> R = 4Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />1 + 4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />5</td></tr></table></div> <br/> = 2.4A <br/> ∴ Therefore, the current through the 12 &#937;  resistor using the current divider rule = <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2.4</td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">6<hr size=\"1\" />12 + 6</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4</td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">6<hr size=\"1\" />18</td></tr></table></div> <br/> = 0.8A</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the curve above, PQRST represents an alternating voltage of frequency 50Hz. The time interval between points P and R on the graph is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25s</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />50</td><td style=\"text-align:center;\">s</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\">s</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />200</td><td style=\"text-align:center;\">s</td></tr></table></div></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">The</td><td style=\"text-align:center;\">period</td><td style=\"text-align:center;\">(from</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">i.e.</td><td style=\"text-align:center;\">one</td><td style=\"text-align:center;\">wavelength)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />50</td><td style=\"text-align:center;\">s</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">But</td><td style=\"text-align:center;\">from</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">R</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">half</td><td style=\"text-align:center;\">wavelength.</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">So</td><td style=\"text-align:center;\">the</td><td style=\"text-align:center;\">time</td><td style=\"text-align:center;\">interval</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />50</td><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">&#247; </td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />100</td><td style=\"text-align:center;\">s</td></tr></table></div></div>", "topic": "SIMPLE A. C. CIRCUITS"}, {"id": "objective>Physics>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the figures below illustrates the dispersion of white light through a triangular glass prism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The figure which illustrates the dispersion of white light through a triangular glass prism is: <br/>  <br/>  <img src=\"1994/jambphyanswerc.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs represents the variation of pressure P against volume V at constant temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to boyle's law pressure is inversely proportional to volume, at constant temperature. <br/>  <img src=\"1994/answerbb.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A volume ofwater is heated from 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.Which of the following diagrams correctly represents the variation ofthe volume with temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"1994/optionbb.png\" style=\"position:relative;max-width:100%;\"/> <br/> Anomalous expansion of water, the volume decreases when heated from 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> to 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> and increases when heated above 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "topic": "THERMAL EXPANSION : LIQUIDS"}, {"id": "objective>Physics>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs correctly represents the relationship between the load and the velocity ratio of a machine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph which correctly represents the relationship between the load and the velocity ratio of a machine is: <br/>  <br/> <img src=\"1994/option1.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone thrown vertically upwards returns to the ground. Which of the following figures represents the velocity-time graph?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the positive region the velocity decreases linearly (during rise) and in the negative region velocity increases linearly(during fall) and the direction is opposite to each other during rise and fall, hence fall is shown in the negative region. Hence ,the correct option is <br/>  <img src=\"1994/jpq50optiond.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "MOTION: MOTION UNDER GRAVITY~~MOTION: LINEAR MOTION"}];
